package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.ArrayCreationExpr;
import com.github.javaparser.ast.expr.IntegerLiteralExpr;
import com.github.javaparser.ast.stmt.ReturnStmt;
import com.github.javaparser.ast.type.ArrayType;
import com.github.javaparser.ast.type.PrimitiveType;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java -jar javaparser.jar <path-to-source-file>");
            System.exit(1);
        }

        String filePath = args[0];
        File sourceFile = new File(filePath);

        if (!sourceFile.exists()) {
            System.err.println("File not found: " + filePath);
            System.exit(1);
        }

        CompilationUnit cu = StaticJavaParser.parse(sourceFile);

        cu.findAll(ClassOrInterfaceDeclaration.class).forEach(classDecl -> {
            if ("LogMessageEncoder".equals(classDecl.getNameAsString())) {
                boolean hasFooterBytes = classDecl.getMethodsByName("footerBytes").isEmpty() == false;

                if (!hasFooterBytes) {
                    MethodDeclaration footerBytesMethod = classDecl.addMethod("footerBytes");
                    footerBytesMethod.setType(new ArrayType(PrimitiveType.BYTE));
                    footerBytesMethod.setPublic(true);
                    footerBytesMethod.addAnnotation("Override");

                    ArrayCreationExpr emptyArray = new ArrayCreationExpr(
                        PrimitiveType.BYTE,
                        java.util.List.of(),
                        new ArrayCreationExpr.Initializer()
                    );
                    ReturnStmt returnStmt = new ReturnStmt(emptyArray);
                    footerBytesMethod.setBody(footerBytesMethod.createBody());
                    footerBytesMethod.getBody().ifPresent(body -> {
                        body.getStatements().clear();
                        body.addStatement(returnStmt);
                    });

                    System.out.println("Added footerBytes() method to LogMessageEncoder");
                } else {
                    System.out.println("footerBytes() method already exists");
                }
            }
        });

        String modifiedCode = cu.toString();
        Files.write(Paths.get(filePath), modifiedCode.getBytes());

        System.out.println("Transformation complete. Modified file: " + filePath);
    }
}

